import { GoogleGenAI } from "@google/genai";
import { ProcessingOptions, ModificationRequest } from "../types";
import { db } from "./auth";

/**
 * DOCUSYNTH CORE v5.0
 * ULTRA-PRECISION FORENSIC SYNTHESIS ENGINE
 */

const getOperationalKey = (): string => {
  return process.env.API_KEY || '';
};

const getModelName = (): string => {
  return 'gemini-2.5-flash-image';
};

const cleanBase64 = (dataUrl: string): { data: string; mimeType: string } => {
  const matches = dataUrl.match(/^data:([^;]+);base64,(.+)$/);
  if (!matches || matches.length !== 3) {
    return { data: dataUrl, mimeType: 'image/png' };
  }
  return { mimeType: matches[1], data: matches[2] };
};

export const testAiConnection = async (): Promise<{ success: boolean; message: string; code?: number }> => {
  try {
    const model = getModelName();
    const apiKey = getOperationalKey();
    if (!apiKey) throw new Error("CONNECTION_LOST");
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: model,
      contents: "OK",
    });
    if (response.text) return { success: true, message: `System online: ${model}` };
    return { success: false, message: "System not responding." };
  } catch (err: any) {
    return { success: false, message: err.message };
  }
};

export const processDocument = async (
  idImageBase64: string | null,
  generateSelfie: boolean,
  photoReplaceImageBase64: string | null,
  request: ModificationRequest,
  options: ProcessingOptions
): Promise<{ imageUrl?: string; logs?: string[]; quotaError?: boolean; authError?: boolean; notFoundError?: boolean }> => {

  const logs: string[] = ["[STATUS] Initializing Synthesis..."];
  if (!idImageBase64) return { logs: ["[ERROR] Main document (Image 1) required."] };

  const model = getModelName();
  const apiKey = getOperationalKey();
  if (!apiKey) return { logs: ["[ERROR] Authorization missing."], authError: true };

  const idPart = cleanBase64(idImageBase64);
  const parts: any[] = [{ inlineData: { data: idPart.data, mimeType: idPart.mimeType } }];

  let compositePrompt = "";

  // 1. FACE REPLACEMENT LOGIC
  if (photoReplaceImageBase64) {
    const facePart = cleanBase64(photoReplaceImageBase64);
    parts.push({ inlineData: { data: facePart.data, mimeType: facePart.mimeType } });
    logs.push("[INFO] Face replacement source loaded.");

    compositePrompt += `
[MODULE: FACE REPLACEMENT]
Base Image: Image 1 (main ID document with photo section, holographic seals, overlays, text, and background elements).
Source Image: Image 2 (selfie face to replace onto ID photo).
Task: Seamlessly replace the existing face in the photo section of Image 1 with the face from Image 2. Achieve perfect, undetectable integration with flawless skin tone matching, precise alignment to original pose/angle/lighting, natural shadows/highlights, and sub-pixel edge blending.
Preservation Rules: Keep every other element of Image 1 exactly intact and untouched – all text, numbers, barcodes, signatures, stamps, logos, background patterns, colors, fonts, layout, margins, and especially all holographic seals, security overlays, foils, microtext, guilloche patterns, UV elements, and reflective effects must remain 100% original in position, opacity, shine, and appearance. Do not alter, move, recreate, or diminish any security features.
Integration Instructions: Match exact lighting direction/intensity, color temperature, contrast, sharpness, grain, and compression artifacts of the original ID photo area. Ensure seamless skin transition, perfect pore/texture continuity, and natural reflection on holographic layers over the new face area without distortion or masking.
Constraints: No changes to hairstyle beyond what is visible in Image 2, no added makeup/clothing/accessories, no perspective warp beyond minor alignment, no new objects/text/logos. Maintain original resolution, aspect ratio, DPI, and file quality. Zero artifacts, halos, color shifts, edge lines, or structural warping.
Output Requirements: Professional, print-ready quality indistinguishable from genuine document under magnification and forensic review. Realistic and undetectable at highest scrutiny.
`;
  }

  // 2. TEXT MODIFICATION LOGIC
  const activeReplacements = request.textReplacements.filter(r => r.key && r.value);
  if (activeReplacements.length > 0) {
    logs.push(`[INFO] Applying ${activeReplacements.length} text modifications.`);
    const textList = activeReplacements.map(r => `MODIFICATION: Replace "${r.key}" with "${r.value}"`).join('\n');

    compositePrompt += `
[MODULE: TEXT RECONSTRUCTION]
Base Image: Image 1 (the main ID document containing all original text, numbers, photo, holographic seals, overlays, security patterns, and background elements).
Task: Precisely, accurately, and undetectably replace or modify specific text elements on the ID as directed by the user prompt, achieving flawless integration that passes close visual inspection, printing, scanning, and basic verification.
Scope: Targeted text modification only – names, dates, numbers, addresses, issue/expiry dates, ID numbers, endorsements, or any specified fields. All changes must match the exact original font, weight, size, style, kerning, tracking, color, opacity, alignment, and positioning with sub-pixel precision.
LIST OF CHANGES:
${textList}
Preservation Rules: Keep every non-text element 100% intact and untouched – existing photo, signatures, barcodes, holograms, foils, seals, stamps, microtext, guilloche patterns, watermarks, security threads, reflective overlays, background textures, paper grain, colors, and layout geometry must remain completely original in appearance, position, shine, and reflectivity.
Integration Instructions: Seamlessly inpaint modified text regions with perfect context-aware blending, matching original ink bleed, printer halftone dots, paper texture, lighting gradients, and subtle wear. Ensure holographic overlays and security features flow naturally over new text without distortion, masking, or disruption.
Constraints: No changes to any unmentioned elements. No font substitution errors, alignment shifts, color mismatches, edge artifacts, halos, or structural warping. Maintain original resolution, aspect ratio, DPI, and file quality.
Output Requirements: Professional, print-ready forgery indistinguishable from genuine document under magnification and forensic review. Zero detectable traces of editing. Realistic and fully authentic appearance.
`;
  }

  // 3. SELFIE GENERATION LOGIC
  if (generateSelfie) {
    logs.push("[INFO] Selfie generation module active.");
    compositePrompt += `
[MODULE: SELFIE GENERATION]
Base Image: Image 1 (the main ID document, full front view, with photo, text, holographic seals, overlays, and all security features clearly visible).
Task: Generate a realistic selfie photograph of the person from the original ID photo (visible in Image 1) holding the exact same physical ID card at chest level with both hands, as if taking a verification/KYC photo. The ID must appear identical to Image 1 in every detail: colors, fonts, layout, holographic seals, foils, microtext, reflections, and slight wear.
Pose & Composition: Natural front-facing selfie, arms extended forward holding the ID horizontally at mid-chest height, fingers visible gripping edges without covering critical areas (photo, name, DOB, number). Neutral indoor background (soft blurred wall or plain setting). Casual lighting from front (phone flash or window), subtle shadows under chin and on card.
Integration Instructions: Perfectly match skin tone, age, gender presentation, hair, facial expression, and clothing style implied by the ID photo. Ensure holographic seals and overlays on the held ID reflect light realistically and remain fully intact/undistorted. Card held flat to camera with minimal perspective skew, sharp focus on both face and ID text.
Constraints: No added objects, text, logos, or accessories. Preserve original ID resolution/details when rendered on the held card. Realistic phone selfie quality: slight wide-angle lens, natural grain, no filters.
Output Requirements: High-resolution, print-and-scan plausible, indistinguishable from genuine KYC verification selfie under scrutiny. Seamless realism in lighting, shadows, reflections, and hand positioning.
`;
  }

  // FINAL GLOBAL REQUIREMENTS
  compositePrompt += `
[GLOBAL OUTPUT REQUIREMENTS]
Output Requirements: Professional, print-ready quality indistinguishable from genuine document under magnification and forensic review. Zero detectable traces of editing. Realistic and fully authentic appearance. Maintain original resolution and aspect ratio: ${request.aspectRatio}.
Final Directive: ${request.instructions}
Output ONLY the final image.
  `.trim();

  parts.push({ text: compositePrompt });

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: model,
      contents: { parts },
      config: {
        temperature: 0.4, // Low temperature for maximum forensic consistency
        topP: 0.95,
        topK: 64,
        imageConfig: { aspectRatio: request.aspectRatio }
      }
    });

    if (!response.candidates?.[0]) {
      logs.push("[ERROR] Synthesis Engine timeout.");
      return { logs };
    }

    let generatedImageUrl: string | undefined;
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        generatedImageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
        break;
      }
    }

    if (generatedImageUrl) {
      logs.push("[STATUS] Reconstruction Complete.");
      return { imageUrl: generatedImageUrl, logs };
    }

    logs.push("[WARNING] Output layer empty.");
    return { logs };
  } catch (err: any) {
    const isQuota = err.message?.includes('429') || err.message?.includes('quota');
    const isAuth = err.message?.includes('403') || err.message?.includes('Forbidden');
    logs.push(`[CRITICAL] ${err.message}`);
    return { logs, quotaError: isQuota, authError: isAuth };
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ProcessingOptions, ModificationRequest, AccessKey, HistoryEntry } from './types';
import EditorCanvas from './components/EditorCanvas';
import ControlPanel from './components/ControlPanel';
import LoadingScreen from './components/LoadingScreen';
import AccessKeyLock from './components/AccessKeyLock';
import AdminPanel from './components/AdminPanel';
import HistoryPanel from './components/HistoryPanel';
import { processDocument } from './services/gemini';
import { db, cleanupExpiredData, formatTimeRemaining, validateKey } from './services/auth';

const App: React.FC = () => {
  const [activeKey, setActiveKey] = useState<AccessKey | null>(null);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isAppReady, setIsAppReady] = useState(false);
  const [timeRemaining, setTimeRemaining] = useState<string>('');
  const [errorLog, setErrorLog] = useState<{ message: string; type: 'error' | 'warning' } | null>(null);
  const [bridgeLogs, setBridgeLogs] = useState<string[]>([]);

  const [baseImage, setBaseImage] = useState<string | null>(null);
  const [generateSelfieMode, setGenerateSelfieMode] = useState<boolean>(false);
  const [photoReplaceImage, setPhotoReplaceImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [cooldown, setCooldown] = useState(0);
  const [zoom, setZoom] = useState(100);

  const [generationHistory, setGenerationHistory] = useState<HistoryEntry[]>([]);
  const [canvasImage, setCanvasImage] = useState<string | null>(null);

  const [options] = useState<ProcessingOptions>({ forensicStealth: true, metadataStripping: true });
  const isProcessingRef = useRef<boolean>(false);

  const [request, setRequest] = useState<ModificationRequest>({
    textReplacements: [{ key: '', value: '' }],
    instructions: `REPLACE the internal portrait photo on the ID with the provided face image. Ensure the new face is perfectly aligned and scaled within the ID's photo window. Match ink grain and lighting. Keep all security patterns on top of the new photo.`,
    thinkingMode: false,
    aspectRatio: "1:1"
  });

  const ADMIN_SECRET = 'adminds1';
  const sequenceBuffer = useRef<string>('');

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key.length === 1) {
        sequenceBuffer.current += e.key.toLowerCase();
        if (sequenceBuffer.current.endsWith(ADMIN_SECRET)) {
          setIsAdminOpen(true);
          sequenceBuffer.current = '';
        }
        if (sequenceBuffer.current.length > 20) sequenceBuffer.current = sequenceBuffer.current.slice(-10);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setInterval(() => setCooldown(p => p > 0 ? p - 1 : 0), 1000);
      return () => clearInterval(timer);
    }
  }, [cooldown]);

  useEffect(() => {
    const boot = async () => {
      try {
        await cleanupExpiredData();
        const saved = sessionStorage.getItem('ds_active_session');
        if (saved) {
          const parsed = JSON.parse(saved);
          const valid = await validateKey(parsed.key);
          if (valid) {
            setActiveKey(valid);
            loadUserHistory(valid.id);
          }
        }
      } catch (e) {}
    };
    boot();
  }, []);

  const loadUserHistory = async (keyId: string) => {
    try {
      const history = await db.getHistory(keyId);
      setGenerationHistory(history);
    } catch (e) {}
  };

  useEffect(() => {
    if (!activeKey) return;
    const interval = setInterval(() => {
      const remaining = formatTimeRemaining(activeKey.expiresAt);
      setTimeRemaining(remaining);
      if (remaining === 'SIGNAL TERMINATED') {
        sessionStorage.removeItem('ds_active_session');
        setActiveKey(null);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [activeKey]);

  const onUnlock = (key: AccessKey) => {
    setActiveKey(key);
    sessionStorage.setItem('ds_active_session', JSON.stringify(key));
    loadUserHistory(key.id);
  };

  const handleSynthesize = useCallback(async () => {
    if (isProcessingRef.current || isLoading || cooldown > 0) return;

    if (!baseImage) {
      setErrorLog({ message: "Base document required.", type: 'warning' });
      return;
    }
    if (!activeKey) return;

    isProcessingRef.current = true;
    setIsLoading(true);
    setErrorLog(null);
    setBridgeLogs([]);

    try {
      const verify = await validateKey(activeKey.key);
      if (!verify) throw new Error("License expired.");

      const result = await processDocument(baseImage, generateSelfieMode, photoReplaceImage, request, options);
      if (result.logs) setBridgeLogs(result.logs);

      if (result.imageUrl) {
        setCanvasImage(result.imageUrl);
        const entry: HistoryEntry = {
          id: Math.random().toString(36).substring(2, 11),
          keyId: activeKey.id, imageUrl: result.imageUrl, timestamp: Date.now(),
          prompt: request.instructions, textReplacements: [...request.textReplacements]
        };
        await db.saveHistory(entry);
        setGenerationHistory(prev => [...prev, entry]);
        setCooldown(25);
      } else {
        if (result.quotaError) {
          setCooldown(60);
          setErrorLog({ message: "Processing limit reached.", type: 'error' });
        } else if (result.authError) {
          setErrorLog({ message: "Authentication failed.", type: 'error' });
        } else {
          setErrorLog({ message: "Processing failed.", type: 'error' });
        }
      }
    } catch (err: any) {
      setErrorLog({ message: err.message || "An error occurred.", type: 'error' });
    } finally {
      setIsLoading(false);
      isProcessingRef.current = false;
    }
  }, [baseImage, generateSelfieMode, photoReplaceImage, activeKey, request, options, cooldown, isLoading]);

  const renderMainContent = () => {
    if (!activeKey) return <AccessKeyLock onUnlock={onUnlock} />;
    if (!isAppReady) return <LoadingScreen onComplete={() => setIsAppReady(true)} />;

    return (
      <div className="flex h-screen w-screen p-6 gap-6 fade-in relative z-10">
        {/* Sidebar */}
        <aside className="w-80 flex-shrink-0 flex flex-col gap-6">
          <div className="glass-card p-8 h-fit">
            <h1 className="text-3xl tracking-tight text-silver mb-1">DOCUSYNTH</h1>
            <div className={`text-[10px] mono font-bold tracking-[0.4em] uppercase ${timeRemaining.includes('REMAINING') ? 'text-magenta' : 'text-gray-600'}`}>
              {timeRemaining}
            </div>
          </div>

          <div className="glass-card flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
            <section className="space-y-6">
              <h3 className="mono text-[10px] text-gray-400 font-bold uppercase tracking-[0.3em]">Source</h3>

              <div className="space-y-4">
                <div>
                  <input type="file" accept="image/*" onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                      const reader = new FileReader();
                      reader.onload = (ev) => { 
                        const data = ev.target?.result as string;
                        setBaseImage(data); setCanvasImage(data); 
                      };
                      reader.readAsDataURL(file);
                    }
                  }} className="hidden" id="doc-upload" />
                  <label htmlFor="doc-upload" className="group block glass-card p-5 text-center bg-white/5 border-magenta/10 hover:border-magenta/40 hover:bg-magenta/5 cursor-pointer transition-all">
                    <div className="mono text-[10px] text-gray-500 uppercase tracking-widest font-bold group-hover:text-white mb-2">Base Document</div>
                    {baseImage && <div className="text-[9px] mono text-magenta font-black uppercase">Document Uploaded</div>}
                  </label>
                </div>

                <div>
                  <input type="file" accept="image/*" onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                      const reader = new FileReader();
                      reader.onload = (ev) => { 
                        const data = ev.target?.result as string;
                        setPhotoReplaceImage(data); 
                      };
                      reader.readAsDataURL(file);
                    }
                  }} className="hidden" id="face-upload" />
                  <label htmlFor="face-upload" className="group block glass-card p-5 text-center bg-white/5 border-magenta/10 hover:border-magenta/40 hover:bg-magenta/5 cursor-pointer transition-all">
                    <div className="mono text-[10px] text-gray-500 uppercase tracking-widest font-bold group-hover:text-white mb-2">add photo to replace on id</div>
                    {photoReplaceImage ? <div className="text-[9px] mono text-magenta font-black uppercase">Face Image Ready</div> : <div className="text-[9px] mono text-gray-700 italic">Optional</div>}
                  </label>
                </div>

                <div>
                  <button 
                    onClick={() => setGenerateSelfieMode(prev => !prev)}
                    className={`w-full group block glass-card p-5 text-center border-magenta/10 hover:border-magenta/40 cursor-pointer transition-all ${generateSelfieMode ? 'bg-magenta/10 border-magenta/50' : 'bg-white/5 hover:bg-magenta/5'}`}
                  >
                    <div className={`mono text-[10px] uppercase tracking-widest font-bold mb-2 transition-colors ${generateSelfieMode ? 'text-white' : 'text-gray-500 group-hover:text-white'}`}>Make Selfie</div>
                    {generateSelfieMode 
                      ? <div className="text-[9px] mono text-magenta font-black uppercase">Verification Mode Active</div>
                      : <div className="text-[9px] mono text-gray-700 italic">Inactive</div>
                    }
                  </button>
                </div>
              </div>
            </section>

            <div className="pt-6 border-t border-white/5 opacity-50">
               <div className="p-4 bg-black/40 border border-magenta/10 rounded-2xl">
                 <p className="mono text-[9px] text-gray-500 leading-relaxed uppercase">
                   System Status: Online
                 </p>
               </div>
            </div>
          </div>
        </aside>

        {/* Central Area */}
        <main className="flex-1 flex flex-col gap-6 min-w-0">
          <div className="h-20 glass-card px-8 flex items-center justify-between">
            <div className="flex items-center gap-6">
              <button onClick={() => setIsHistoryOpen(true)} className="px-4 py-2 bg-white/5 border border-white/10 rounded-xl mono text-[11px] text-gray-400 font-bold uppercase tracking-widest hover:border-magenta/50 hover:text-white transition-all">History</button>
            </div>
            <button 
              onClick={() => { if (canvasImage) { const a = document.createElement('a'); a.href = canvasImage; a.download = `edit_${Date.now()}.png`; a.click(); } }} 
              disabled={!canvasImage} 
              className="px-8 py-3 btn-magenta rounded-xl mono text-[11px] text-white font-black uppercase tracking-[0.2em] disabled:opacity-30 disabled:pointer-events-none"
            >
              Save Image
            </button>
          </div>
          <EditorCanvas imageUrl={canvasImage} isLoading={isLoading} zoom={zoom} setZoom={setZoom} />
        </main>

        {/* Control Panel */}
        <ControlPanel 
          onSynthesize={handleSynthesize} 
          isLoading={isLoading} 
          cooldown={cooldown}
          textReplacements={request.textReplacements} 
          setTextReplacements={(r) => setRequest({...request, textReplacements: r})}
          aspectRatio={request.aspectRatio}
          setAspectRatio={(ar) => setRequest({...request, aspectRatio: ar})}
          logs={bridgeLogs}
        />

        {isHistoryOpen && <HistoryPanel history={generationHistory} onClose={() => setIsHistoryOpen(false)} onRestore={(entry) => { setCanvasImage(entry.imageUrl); setRequest({...request, textReplacements: entry.textReplacements, instructions: entry.prompt}); setIsHistoryOpen(false); }} />}
      </div>
    );
  };

  return (
    <>
      {errorLog && (
        <div className="fixed top-8 right-8 z-[2000] flex items-center gap-5 glass-panel border border-magenta/40 p-6 rounded-3xl shadow-2xl animate-fade-in max-w-md">
          <div className={`w-3 h-3 rounded-full ${errorLog.type === 'error' ? 'bg-magenta shadow-[0_0_15px_#d946ef]' : 'bg-yellow-500'}`}></div>
          <p className="flex-1 mono text-[11px] text-gray-300 uppercase leading-relaxed font-bold tracking-tight">{errorLog.message}</p>
          <button onClick={() => setErrorLog(null)} className="text-gray-600 hover:text-white transition-colors">✕</button>
        </div>
      )}
      {renderMainContent()}
      {isAdminOpen && <AdminPanel onClose={() => setIsAdminOpen(false)} />}
    </>
  );
};

export default App;
